import { execFileSync } from "node:child_process";
import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, it } from "vitest";

/**
 * D1 — the demo CLI as a real child process (plan §5 D1; C7 deterministic $0).
 * `demo` exits 0, prints the byte-frozen golden text; `demo --json` prints the
 * byte-frozen golden transcript JSON; strict-flag discipline mirrors the check
 * legs (any non-`--json` flag or positional exits 2 loudly). The goldens are
 * regenerated by `npm run fixtures:demo`; this locks them.
 */

const root = process.cwd();
const cli = join(root, "bin", "check.mjs");
const fixtures = join(root, "fixtures", "synthetic-restaurant");

interface RunResult {
  readonly status: number;
  readonly stdout: string;
}

function runCli(args: readonly string[]): RunResult {
  try {
    const stdout = execFileSync(process.execPath, [cli, ...args], { encoding: "utf8" });
    return { status: 0, stdout };
  } catch (err) {
    const e = err as { status?: number; stdout?: string };
    return { status: e.status ?? -1, stdout: e.stdout ?? "" };
  }
}

describe("D1 demo CLI (real process)", () => {
  it("`demo` exits 0 and prints the byte-frozen golden text", () => {
    const r = runCli(["demo"]);
    expect(r.status).toBe(0);
    expect(r.stdout).toBe(readFileSync(join(fixtures, "expected-demo.txt"), "utf8"));
  }, 60000);

  it("`demo --json` exits 0 and prints the byte-frozen golden transcript JSON", () => {
    const r = runCli(["demo", "--json"]);
    expect(r.status).toBe(0);
    expect(r.stdout).toBe(readFileSync(join(fixtures, "expected-demo.json"), "utf8"));
    // Valid, parseable JSON carrying the C7 claim + simulated label.
    const t = JSON.parse(r.stdout) as { claim: string; simulated: boolean; beats: unknown[] };
    expect(t.simulated).toBe(true);
    expect(t.beats).toHaveLength(4);
  }, 60000);

  it("`demo` accepts only --json: a mixed/unknown flag exits 2 (never silent)", () => {
    expect(runCli(["demo", "--against", "x.json"]).status).toBe(2);
    expect(runCli(["demo", "--surface", "ucp"]).status).toBe(2);
    expect(runCli(["demo", "--jsn"]).status).toBe(2);
  }, 60000);

  it("`demo` rejects surplus positionals (exit 2)", () => {
    expect(runCli(["demo", "extra.json"]).status).toBe(2);
  }, 60000);
});
